    enterprise_entity_dim_v.ENTITY_DIVISION_DESCRIPTION AS OWN_FA_ENT_DIV_DSC,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_DIVISION_DESCRIPTION
    enterprise_entity_dim_v.ENTITY_DIVISION_NODE AS OWN_FA_ENT_DIV_NODE,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_DIVISION_NODE
    enterprise_entity_dim_v.ENTITY_MAIN_BRANCH_STATE AS OWN_FA_ENT_MAIN_BR_STE,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_MAIN_BRANCH_STATE
    enterprise_entity_dim_v.ENTITY_OSJ       AS OWN_FA_ENT_OSJ,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_OSJ
    eerdv.ENTITY_RETAIL_BUSINESS_MODEL_CODE  AS OWN_FA_ENT_RTL_HIER_BSN_MODL_CD,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RETAIL_DIMENSION_V.ENTITY_RETAIL_BUSINESS_MODEL_CODE
    eerdv.ENTITY_RETAIL_BUSINESS_MODEL_DESCRIPTION AS OWN_FA_ENT_RTL_HIER_BSN_MODL_DSC,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RETAIL_DIMENSION_V.ENTITY_RETAIL_BUSINESS_MODEL_DESCRIPTION
