    eerdv.ENTITY_RETAIL_SALES_DIVISION_CODE  AS OWN_FA_ENT_RTL_SALE_DIV_CD,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RETAIL_DIMENSION_V.ENTITY_RETAIL_SALES_DIVISION_CODE
    eerdv.ENTITY_RETAIL_SALES_REGION_CODE    AS OWN_FA_ENT_RTL_SALE_HIER_RGON_CD,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RETAIL_DIMENSION_V.ENTITY_RETAIL_SALES_REGION_CODE
    eerdv.ENTITY_RETAIL_SALES_REGION_DESCRIPTION AS OWN_FA_ENT_RTL_SALE_HIER_RGON_DSC,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RETAIL_DIMENSION_V.ENTITY_RETAIL_SALES_REGION_DESCRIPTION
    eerdv.ENTITY_RETAIL_TERRITORY_CODE       AS OWN_FA_ENT_RTL_HIER_TERR_CD,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RETAIL_DIMENSION_V.ENTITY_RETAIL_TERRITORY_CODE
    eerdv.ENTITY_RETAIL_TERRITORY_DESCRIPTION AS OWN_FA_ENT_RTL_HIER_TERR_DSC,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RETAIL_DIMENSION_V.ENTITY_RETAIL_TERRITORY_DESCRIPTION
    ar_grp_subdim.ENTITY_RISK_BUSINESS_UNIT_CODE AS OWN_FA_ENT_RSK_HIER_BSN_UNIT_CD,  -- [DRD_INLINE_FALLBACK] DRD inline join CCSI_OWNER.AR_GRP_SUBDIM.ENTITY_RISK_BUSINESS_UNIT_CODE (ODI ref to SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RISK_DIM skipped: no JOIN)
    ar_grp_subdim.ENTITY_RISK_BUSINESS_UNIT_DESCRIPTION AS OWN_FA_ENT_RSK_HIER_BSN_UNIT_DSC,  -- [DRD_INLINE_FALLBACK] DRD inline join CCSI_OWNER.AR_GRP_SUBDIM.ENTITY_RISK_BUSINESS_UNIT_DESCRIPTION (ODI ref to SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RISK_DIM skipped: no JOIN)
    enterprise_entity_dim_v.ENTITY_RJAS_ID_BOOLEAN AS OWN_FA_ENT_RJAS_ID_F,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_RJAS_ID_BOOLEAN
    enterprise_entity_dim_v.ENTITY_SUBDIVISION_CODE AS OWN_FA_ENT_SUBDIV_CD,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_SUBDIVISION_CODE
    enterprise_entity_dim_v.ENTITY_SUBDIVISION_DESCRIPTION AS OWN_FA_ENT_SUBDIV_DSC,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_SUBDIVISION_DESCRIPTION
    enterprise_entity_dim_v.ENTITY_SUBSIDIARY AS OWN_FA_ENT_SUBS,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_SUBSIDIARY
    enterprise_entity_dim_v.ENTITY_SUBTYPE   AS OWN_FA_ENT_SBTP,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_SUBTYPE
    enterprise_entity_dim_v.ENTITY_SUBTYPE_CODE AS OWN_FA_ENT_SBTP_CD,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_SUBTYPE_CODE
    enterprise_entity_dim_v.ENTITY_TYPE      AS OWN_FA_ENT_TP,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_TYPE
    enterprise_entity_dim_v.ENTITY_TYPE_CODE AS OWN_FA_ENT_TP_CD,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_TYPE_CODE
    enterprise_entity_dim_v.LOB_ALEX_BROWN_BOOLEAN AS OWN_FA_ENT_LOB_AB_F,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.LOB_ALEX_BROWN_BOOLEAN
    enterprise_entity_dim_v.LOB_AMS_BOOLEAN  AS OWN_FA_ENT_LOB_AMS_F,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.LOB_AMS_BOOLEAN
    enterprise_entity_dim_v.LOB_BUSINESS_MODEL AS OWN_FA_ENT_LOB_BSN_MODL,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.LOB_BUSINESS_MODEL
    enterprise_entity_dim_v.ENTITY_BUSINESS_OPEN_DATE AS OWN_FA_ENT_BSN_OPN_DT,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_BUSINESS_OPEN_DATE
    enterprise_entity_dim_v.ENTITY_CODE_LONG AS OWN_FA_ENT_LONG_CD,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_CODE_LONG
    enterprise_entity_dim_v.ENTITY_CODE_SHORT AS OWN_FA_ENT_SHRT_CD,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_CODE_SHORT
    enterprise_entity_dim_v.ENTITY_CSS_ID    AS OWN_FA_ENT_CSS_ID,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V.ENTITY_CSS_ID
    eerdv.ENTITY_RETAIL_SALES_COMPLEX_CODE   AS OWN_FA_ENT_RTL_SALE_CPX_CD,  -- [DRD_PHYSICAL] DRD source SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RETAIL_DIMENSION_V.ENTITY_RETAIL_SALES_COMPLEX_CODE
    imt_pd_dim.EQTY_SECT_LVL_4               AS EQTY_IDY,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.EQTY_SECT_LVL_4
    imt_pd_dim.EQTY_SECT_LVL_4_CD            AS EQTY_IDY_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.EQTY_SECT_LVL_4_CD
    imt_pd_dim.EQTY_SECT_LVL_3               AS EQTY_IDY_GRP,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.EQTY_SECT_LVL_3
    imt_pd_dim.EQTY_SECT_LVL_3_CD            AS EQTY_IDY_GRP_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.EQTY_SECT_LVL_3_CD
    imt_pd_dim.EQTY_SECT_LVL_2               AS EQTY_SECT,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.EQTY_SECT_LVL_2
    imt_pd_dim.EQTY_SECT_LVL_2_CD            AS EQTY_SECT_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.EQTY_SECT_LVL_2_CD
    imt_pd_dim.EQTY_SECT_LVL_1               AS EQTY_SUP_SECT,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.EQTY_SECT_LVL_1
    imt_pd_dim.EQTY_SECT_LVL_1_CD            AS EQTY_SUP_SECT_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.EQTY_SECT_LVL_1_CD
    imt_pd_dim.FIRM_MODL_LVL_2               AS MODL_STRTG_DTL_AST_CLSS,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.FIRM_MODL_LVL_2
    imt_pd_dim.FIRM_MODL_LVL_2_CD            AS MODL_STRTG_DTL_AST_CLSS_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.FIRM_MODL_LVL_2_CD
    imt_pd_dim.FIRM_MODL_LVL_1               AS MODL_STRTG_SMY_AST_CLSS,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.FIRM_MODL_LVL_1
    imt_pd_dim.FIRM_MODL_LVL_1_CD            AS MODL_STRTG_SMY_AST_CLSS_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.FIRM_MODL_LVL_1_CD
    apa.PD_CMPOS_DSC                         AS PD_CMPOS_DSC,  -- [ODI] ODI staging chain -> CCAL_REPL_OWNER.APA.PD_CMPOS_DSC /* see ETL block PRODUCT_INFORMATION in header */
    imt_pd_dim.PD_NM                         AS PD_SHRT_NM,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.PD_NM /* see ETL block PRODUCT_INFORMATION in header */
    imt_pd_dim.PD_DSC                        AS PD_DSC,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.PD_DSC /* see ETL block PRODUCT_INFORMATION in header */
    imt_pd_dim.RPT_CL_LVL_1                  AS RPT_CL_LVL_1,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.RPT_CL_LVL_1
    imt_pd_dim.RPT_CL_LVL_2                  AS RPT_CL_LVL_2,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.RPT_CL_LVL_2
    imt_pd_dim.FIRM_RPT_LVL_2                AS RPT_STRTG_DTL_AST_CLSS,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.FIRM_RPT_LVL_2
    imt_pd_dim.FIRM_RPT_LVL_2_CD             AS RPT_STRTG_DTL_AST_CLSS_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.FIRM_RPT_LVL_2_CD
    imt_pd_dim.FIRM_RPT_LVL_1                AS RPT_STRTG_SMY_AST_CLSS,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.FIRM_RPT_LVL_1
    imt_pd_dim.FIRM_RPT_LVL_1_CD             AS RPT_STRTG_SMY_AST_CLSS_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.FIRM_RPT_LVL_1_CD
    imt_pd_dim.FND_FAM                       AS FND_FAM,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.FND_FAM
    imt_pd_dim.SHR_CLSS_TP_CD                AS SHR_CLSS_TP_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.SHR_CLSS_TP_CD
    imt_pd_dim.SHR_CLSS_TP_NM                AS SHR_CLSS_TP,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.SHR_CLSS_TP_NM
    imt_pd_dim.IMT_CL_LVL_1                  AS IMT_CL_LVL_1,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.IMT_CL_LVL_1
    imt_pd_dim.IMT_CL_LVL_1_CD               AS IMT_CL_LVL_1_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.IMT_CL_LVL_1_CD
    imt_pd_dim.IMT_CL_LVL_2                  AS IMT_CL_LVL_2,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.IMT_CL_LVL_2
    imt_pd_dim.IMT_CL_LVL_2_CD               AS IMT_CL_LVL_2_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.IMT_CL_LVL_2_CD
    imt_pd_dim.IMT_CL_LVL_3                  AS IMT_CL_LVL_3,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.IMT_CL_LVL_3
    imt_pd_dim.IMT_CL_LVL_3_CD               AS IMT_CL_LVL_3_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.IMT_CL_LVL_3_CD
    imt_pd_dim.IMT_CL_LVL_4                  AS IMT_CL_LVL_4,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.IMT_CL_LVL_4
    imt_pd_dim.IMT_CL_LVL_4_CD               AS IMT_CL_LVL_4_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.IMT_CL_LVL_4_CD
    imt_pd_dim.IMT_CL_LVL_5                  AS IMT_CL_LVL_5,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.IMT_CL_LVL_5
    imt_pd_dim.IMT_CL_LVL_5_CD               AS IMT_CL_LVL_5_CD,  -- [ODI] ODI staging chain -> CIRD_OWNER.IMT_PD_DIM.IMT_CL_LVL_5_CD
    fa_number_v.FA_NUMBER_TYPE_CODE          AS OWN_FA_NUM_TP_CD,  -- [ODI] ODI staging chain -> SSDS_DAL_OWNER.FA_NUMBER_V.FA_NUMBER_TYPE_CODE
    code_set_value_v.CODE_VALUE_DESCRIPTION  AS OWN_FA_NUM_TP,  -- [ODI] ODI staging chain -> SSDS_DAL_OWNER.CODE_SET_VALUE_V.CODE_VALUE_DESCRIPTION
    CASE WHEN cv.CL_VAL_CODE = 'APACSH82' THEN apa.ORIG_QTY ELSE NULL END AS BOND_ACRTN_DCN_AMT,  -- [DRD_PHYSICAL_CASE] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY (applicable only for APACSH82) /* see ETL block APACASH in header */
    CASE WHEN cv.CL_VAL_CODE = 'APACSH83' THEN apa.ORIG_QTY ELSE NULL END AS BOND_AMRZ_PREM_AMT,  -- [DRD_PHYSICAL_CASE] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY (applicable only for APACSH83) /* see ETL block APACASH in header */
    CASE WHEN cv.CL_VAL_CODE = 'APACSH84' THEN apa.ORIG_QTY ELSE NULL END AS RJ_TRUST_BOOK_VAL_AMT,  -- [DRD_PHYSICAL_CASE] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY (applicable only for APACSH84) /* see ETL block APACASH in header */
    CASE WHEN cv.CL_VAL_CODE = 'APACSH85' THEN apa.ORIG_QTY ELSE NULL END AS RJ_TRUST_RLZD_TAX_GAIN_OR_LOSS_AMT,  -- [DRD_PHYSICAL_CASE] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY (applicable only for APACSH85) /* see ETL block APACASH in header */
    CASE WHEN CL_VAL.CL_VAL_CODE = 'APASEC81' THEN apa.ORIG_QTY ELSE NULL END AS BFR_REPYMT_FACE_VAL_AMT,  -- [DRD_PHYSICAL_CASE] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY (applicable only for APASEC81) /* see ETL block PRODUCT_INFORMATION in header */
    CASE WHEN CL_VAL.CL_VAL_CODE = 'APASEC83' THEN apa.ORIG_QTY ELSE NULL END AS BFR_INCM_PYMT_FACE_VAL_AMT,  -- [DRD_PHYSICAL_CASE] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY (applicable only for APASEC83) /* see ETL block PRODUCT_INFORMATION in header */
    CASE WHEN CL_VAL.CL_VAL_CODE = 'APASEC91' THEN apa.ORIG_QTY ELSE NULL END AS BASE_POS_QTY,  -- [DRD_PHYSICAL_CASE] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY (applicable only for APASEC91) /* see ETL block PRODUCT_INFORMATION in header */
    CASE WHEN CL_VAL.CL_VAL_CODE = 'APASEC93' THEN apa.ORIG_QTY ELSE NULL END AS NO_SIS_SCR_MVMT_TXN_QTY,  -- [DRD_PHYSICAL_CASE] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY (applicable only for APASEC93) /* see ETL block PRODUCT_INFORMATION in header */
    CASE WHEN CL_VAL.CL_VAL_CODE = 'APASEC93' THEN apa.SCR_PRC_IN_TXN_CCY ELSE NULL END AS NO_SIS_SCR_MVMT_TXN_PRC,  -- [DRD_PHYSICAL_CASE] DRD source CCAL_REPL_OWNER.APA.SCR_PRC_IN_TXN_CCY (applicable only for APASEC93) /* see ETL block PRODUCT_INFORMATION in header */
    CASE WHEN CL_VAL.CL_VAL_CODE = 'APASEC94' THEN apa.ORIG_QTY ELSE NULL END AS REIVS_SHR_QTY,  -- [DRD_PHYSICAL_CASE] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY (applicable only for APASEC94) /* see ETL block PRODUCT_INFORMATION in header */
    CASE WHEN CL_VAL.CL_VAL_CODE = 'APASEC94' THEN apa.SCR_PRC_IN_TXN_CCY ELSE NULL END AS REIVS_PRC  -- [DRD_PHYSICAL_CASE] DRD source CCAL_REPL_OWNER.APA.SCR_PRC_IN_TXN_CCY (applicable only for APASEC94) /* see ETL block PRODUCT_INFORMATION in header */
FROM CCAL_REPL_OWNER.TXN t
LEFT JOIN CCAL_REPL_OWNER.TXN TXN ON J_AVY_FACT.TXN_ID = TXN.TXN_ID
LEFT JOIN CCAL_REPL_OWNER.APA APA ON TXN.TXN_ID = APA.EXEC_ID AND apa.exec_id = t.txn_id
LEFT JOIN CCAL_REPL_OWNER.TXN_AVY_CL TXN_AVY_CL ON TXN.TXN_ID = TXN_AVY_CL.TXN_ID AND APA.EXEC_ID = TXN_AVY_CL.EXEC_ID AND APA.APA_ID = TXN_AVY_CL.APA_ID AND txn_avy_cl.txn_id = t.txn_id AND apa.apa_id = txn_avy_cl.apa_id
LEFT JOIN CCAL_REPL_OWNER.AVY_CL AVY_CL ON TXN_AVY_CL.AVY_CL_ID = AVY_CL.AVY_CL_ID AND avy_cl.avy_cl_id = txn_avy_cl.avy_cl_id
LEFT JOIN CIRD_OWNER.IMT_PD_DIM SEC_IMT_PD_DIM ON APA.PD_ID = SEC_IMT_PD_DIM.CCAL_PD_ID AND sec_imt_pd_dim.CCAL_PD_ID = apa.PD_ID AND ap.pd_id = sec_imt_pd_dim.ccal_pd_id
LEFT JOIN CIRD_OWNER.CCY_DIM SEC_CCY_DIM ON APA.STM_BASE_ISO_CCY_CODE = SEC_CCY_DIM.CCY_CD AND apa.stm_base_iso_ccy_code = sec_ccy_dim.ccy_cd
LEFT JOIN COMMON_OWNER.ACG_TP_DIM ACG_TP_DIM ON APA.ACG_TP_ID = ACG_TP_DIM.ACG_TP_ID AND apa.ACG_TP_ID = acg_tp_dim.ACG_TP_ID
LEFT JOIN CCSI_OWNER.AR_DIM OFST_AR_DIM ON APA.OFST_AR_ID = OFST_AR_DIM.AR_ID AND apa.OFST_AR_ID = ofst_ar_dim.AR_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL ASSET_PACKAGE_TYPE ON APA.APA_TP_ID = ASSET_PACKAGE_TYPE.CL_VAL_ID AND apa.APA_TP_ID = asset_package_type.CL_VAL_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL DEBIT_CREDIT_TYPES ON APA.DB_CR_ID = DEBIT_CREDIT_TYPES.CL_VAL_ID AND apa.db_cr_id = debit_credit_types.cl_val_id AND debit_credit_types.cl_val_id = apa.db_cr_id
LEFT JOIN COMMON_OWNER.CASH_POS_TP_DIM CASH_POS_TP_DIM ON APA.CASH_POS_TP_ID = CASH_POS_TP_DIM.CASH_POS_TP_ID AND apa.CASH_POS_TP_ID = cash_pos_tp_dim.CASH_POS_TP_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL SALE_CHARGE_RATE_TYPE ON APA.SALE_CHRG_RATE_TP_ID = SALE_CHARGE_RATE_TYPE.CL_VAL_ID AND sale_charge_rate_type.cl_val_id = apa.sale_chrg_rate_tp_id
LEFT JOIN CCAL_REPL_OWNER.CCAL_CIRD_PD_MAP CCAL_CIRD_PD_MAP ON APA.PD_ID = CCAL_CIRD_PD_MAP.CCAL_PD_ID AND apa.pd_id = ccal_cird_pd_map.ccal_pd_id AND ccal_cird_pd_map.ccal_pd_id = apa.pd_id AND ap.pd_id = ccal_cird_pd_map.ccal_pd_id
LEFT JOIN CIRD_OWNER.IMT_PD_DIM IMT_PD_DIM ON CCAL_CIRD_PD_MAP.CIRD_PD_ID = IMT_PD_DIM.CIRD_PD_ID AND ccal_cird_pd_map.cird_pd_id = imt_pd_dim.cird_pd_id
LEFT JOIN CIRD_OWNER.CCY_DIM CCY_DIM ON APA.TXN_ISO_CCY_CODE = CCY_DIM.CCY_CD AND ccy_dim.ccy_cd = apa.txn_iso_ccy_code
LEFT JOIN CCAL_REPL_OWNER.FIP FIP ON APA.APA_ID = FIP.APA_ID
LEFT JOIN CCAL_REPL_OWNER.NNA_CGY NNA_CGY ON TXN_AVY_CL.NNA_CGY_ID = NNA_CGY.NNA_CGY_ID
LEFT JOIN REFERENCE_REPL_OWNER.CCY CCY ON APA.ORIG_CCY_ID = CCY.CCY_ISO_NUM_CODE AND apa.orig_ccy_id = ccy.CCY_ISO_NUM_CODE AND apa.txn_iso_ccy_code = ccy.CCY_CODE
